# Unit Tests for `clamp` Function

```python
import math
import pytest


def clamp(value: float, min_val: float, max_val: float) -> float:
    return max(min_val, min(value, max_val))


class TestClampHappyPath:
    """Tests for typical, expected use cases."""

    def test_value_within_range(self):
        assert clamp(5.0, 0.0, 10.0) == 5.0

    def test_value_below_min(self):
        assert clamp(-5.0, 0.0, 10.0) == 0.0

    def test_value_above_max(self):
        assert clamp(15.0, 0.0, 10.0) == 10.0

    def test_value_equals_min(self):
        assert clamp(0.0, 0.0, 10.0) == 0.0

    def test_value_equals_max(self):
        assert clamp(10.0, 0.0, 10.0) == 10.0

    def test_integer_inputs(self):
        # Function should work with ints since they are subtypes of float
        assert clamp(5, 1, 10) == 5
        assert clamp(0, 1, 10) == 1
        assert clamp(20, 1, 10) == 10

    def test_negative_range(self):
        assert clamp(-5.0, -10.0, -1.0) == -5.0
        assert clamp(-15.0, -10.0, -1.0) == -10.0
        assert clamp(0.0, -10.0, -1.0) == -1.0

    def test_floating_point_precision(self):
        assert clamp(0.1 + 0.2, 0.0, 1.0) == pytest.approx(0.3)

    def test_very_small_range(self):
        assert clamp(0.5, 0.4999, 0.5001) == 0.5


class TestClampEdgeCases:
    """Edge cases involving extreme or boundary values."""

    def test_min_equals_max(self):
        # Range collapses to a single value
        assert clamp(5.0, 3.0, 3.0) == 3.0
        assert clamp(2.0, 3.0, 3.0) == 3.0
        assert clamp(3.0, 3.0, 3.0) == 3.0

    def test_zero_value(self):
        assert clamp(0.0, -1.0, 1.0) == 0.0

    def test_large_values(self):
        assert clamp(1e308, 0.0, 1e307) == 1e307
        assert clamp(1e306, 0.0, 1e307) == 1e306

    def test_small_values(self):
        assert clamp(1e-308, 0.0, 1.0) == 1e-308

    def test_positive_infinity_value(self):
        assert clamp(math.inf, 0.0, 100.0) == 100.0

    def test_negative_infinity_value(self):
        assert clamp(-math.inf, 0.0, 100.0) == 0.0

    def test_infinity_bounds(self):
        assert clamp(42.0, -math.inf, math.inf) == 42.0
        assert clamp(math.inf, -math.inf, math.inf) == math.inf
        assert clamp(-math.inf, -math.inf, math.inf) == -math.inf

    def test_negative_zero(self):
        # -0.0 == 0.0 in Python equality
        assert clamp(-0.0, 0.0, 1.0) == 0.0

    def test_boolean_inputs(self):
        # bool is a subclass of int; behavior is well-defined
        assert clamp(True, 0, 10) == 1
        assert clamp(False, 0, 10) == 0


class TestClampErrorCases:
    """Cases that produce surprising or erroneous behavior."""

    def test_inverted_range_returns_min(self):
        # When min_val > max_val, the function returns min_val regardless of value.
        # This documents the current (mathematically undefined) behavior.
        assert clamp(5.0, 10.0, 0.0) == 10.0
        assert clamp(-100.0, 10.0, 0.0) == 10.0
        assert clamp(100.0, 10.0, 0.0) == 10.0

    def test_nan_value_propagation(self):
        # NaN comparisons always return False, leading to undefined-but-deterministic behavior.
        result = clamp(math.nan, 0.0, 10.0)
        # Per Python's max/min semantics with NaN, result is NaN here
        assert math.isnan(result)

    def test_nan_min_propagation(self):
        result = clamp(5.0, math.nan, 10.0)
        assert math.isnan(result)

    def test_nan_max_propagation(self):
        result = clamp(5.0, 0.0, math.nan)
        # min(5.0, nan) returns 5.0 in CPython, then max(0.0, 5.0) == 5.0
        # but this is implementation-dependent; just ensure no crash
        assert result == 5.0 or math.isnan(result)

    def test_string_input_raises_type_error(self):
        with pytest.raises(TypeError):
            clamp("5", 0.0, 10.0)

    def test_none_input_raises_type_error(self):
        with pytest.raises(TypeError):
            clamp(None, 0.0, 10.0)

    def test_missing_arguments_raises_type_error(self):
        with pytest.raises(TypeError):
            clamp(5.0)  # type: ignore[call-arg]

        with pytest.raises(TypeError):
            clamp(5.0, 0.0)  # type: ignore[call-arg]


